#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#define MAX 100
#define MAX_DIGITS 10

int **board;
int n, m;

int isValid(int x, int y) {
    return x >= 0 && x < n && y >= 0 && y < m;
}

int canRead(int num) {
    int len = 0;
    int temp = num;
    while (temp > 0) {
        len++;
        temp /= 10;
    }
    int *digits = (int *)malloc(len * sizeof(int));
    for (int i = len - 1; i >= 0; i--) {
        digits[i] = num % 10;
        num /= 10;
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (board[i][j] == digits[0]) {
                int **visited = (int **)malloc(n * sizeof(int *));
                for (int k = 0; k < n; k++) {
                    visited[k] = (int *)malloc(m * sizeof(int));
                    for (int l = 0; l < m; l++) {
                        visited[k][l] = 0;
                    }
                }
                visited[i][j] = 1;
                int found = 1;
                for (int k = 1; k < len; k++) {
                    found = 0;
                    for (int x = -1; x <= 1; x++) {
                        for (int y = -1; y <= 1; y++) {
                            if (abs(x) + abs(y) == 1 && isValid(i + x, j + y) && board[i + x][j + y] == digits[k] && !visited[i + x][j + y]) {
                                visited[i + x][j + y] = 1;
                                found = 1;
                                i += x;
                                j += y;
                                break;
                            }
                        }
                        if (found) break;
                    }
                    if (!found) break;
                }
                for (int k = 0; k < n; k++) {
                    free(visited[k]);
                }
                free(visited);
                if (found) return 1;
            }
        }
    }
    free(digits);
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d", &n, &m);
        board = (int **)malloc(n * sizeof(int *));
        for (int i = 0; i < n; i++) {
            board[i] = (int *)malloc(m * sizeof(int));
            char str[MAX];
            scanf("%s", str);
            for (int j = 0; j < m; j++) {
                board[i][j] = str[j] - '0';
            }
        }
        int num = 1;
        while (canRead(num)) num++;
        printf("%d\n", num);
        for (int i = 0; i < n; i++) {
            free(board[i]);
        }
        free(board);
    }
    return 0;
}

