bool canRead(int num) {
    int len = 0;
    int temp = num;
    while (temp > 0) {
        len++;
        temp /= 10;
    }
    vector<int> digits(len);
    for (int i = len - 1; i >= 0; i--) {
        digits[i] = num % 10;
        num /= 10;
    }
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < m; j++) {
            if (board[i][j] == digits[0]) {
                vector<vector<bool>> visited(n, vector<bool>(m, false));
                visited[i][j] = true;
                queue<pair<int, int>> q;
                q.push({i, j});
                int found = 1;
                for (int k = 1; k < len; k++) {
                    found = 0;
                    queue<pair<int, int>> newQ;
                    while (!q.empty()) {
                        int x = q.front().first;
                        int y = q.front().second;
                        q.pop();
                        for (int dx = -1; dx <= 1; dx++) {
                            for (int dy = -1; dy <= 1; dy++) {
                                if (abs(dx) + abs(dy) == 1 && x + dx >= 0 && x + dx < n && y + dy >= 0 && y + dy < m && board[x + dx][y + dy] == digits[k] && !visited[x + dx][y + dy]) {
                                    visited[x + dx][y + dy] = true;
                                    newQ.push({x + dx, y + dy});
                                    found = 1;
                                }
                            }
                        }
                    }
                    q = newQ;
                    if (!found) break;
                }
                if (found) return true;
            }
        }
    }
    return false;
}

