import java.util.Queue;
import java.util.LinkedList;
import java.util.Scanner;

public class Main {
    static int n, m;
    static int[][] board;

    public static boolean canRead(int num) {
        int len = 0;
        int temp = num;
        while (temp > 0) {
            len++;
            temp /= 10;
        }
        int[] digits = new int[len];
        for (int i = len - 1; i >= 0; i--) {
            digits[i] = num % 10;
            num /= 10;
        }
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < m; j++) {
                if (board[i][j] == digits[0]) {
                    boolean[][] visited = new boolean[n][m];
                    visited[i][j] = true;
                    Queue<int[]> q = new LinkedList<>();
                    q.add(new int[] {i, j});
                    boolean found = true;
                    for (int k = 1; k < len; k++) {
                        found = false;
                        Queue<int[]> newQ = new LinkedList<>();
                        while (!q.isEmpty()) {
                            int[] arr = q.poll();
                            int x = arr[0];
                            int y = arr[1];
                            for (int dx = -1; dx <= 1; dx++) {
                                for (int dy = -1; dy <= 1; dy++) {
                                    if (Math.abs(dx) + Math.abs(dy) == 1 && x + dx >= 0 && x + dx < n && y + dy >= 0 && y + dy < m && board[x + dx][y + dy] == digits[k] && !visited[x + dx][y + dy]) {
                                        visited[x + dx][y + dy] = true;
                                        newQ.add(new int[] {x + dx, y + dy});
                                        found = true;
                                    }
                                }
                            }
                        }
                        q = newQ;
                        if (!found) break;
                    }
                    if (found) return true;
                }
            }
        }
        return false;
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            n = sc.nextInt();
            m = sc.nextInt();
            board = new int[n][m];
            for (int i = 0; i < n; i++) {
                String str = sc.next();
                for (int j = 0; j < m; j++) {
                    board[i][j] = str.charAt(j) - '0';
                }
            }
            int num = 1;
            while (canRead(num)) num++;
            System.out.println(num);
        }
    }
}

